index 5226aeb66f65..2bc6dba914f2 100644
--- a/llvm/lib/Transforms/Scalar/CorrelatedValuePropagation.cpp
+++ b/llvm/lib/Transforms/Scalar/CorrelatedValuePropagation.cpp
@@ -1212,24 +1212,94 @@ static bool processAnd(BinaryOperator *BinOp, LazyValueInfo *LVI) {
 }

 static bool processTrunc(TruncInst *TI, LazyValueInfo *LVI) {
+  // Be conservative when deducing NUW/NSW for trunc. Only set flags when we
+  // can prove that the source value always fits into the destination type
+  // range for the respective signedness. This avoids introducing poison when
+  // the value may be out-of-range.
   if (TI->hasNoSignedWrap() && TI->hasNoUnsignedWrap())
     return false;

+  Value *Op = TI->getOperand(0);
+  Type *DestTy = TI->getDestTy();
+  unsigned DestWidth = DestTy->getScalarSizeInBits();
+  bool Changed = false;
+
+  // Handle round-trip cases from zext/sext first.
+  if (auto *ZI = dyn_cast<ZExtInst>(Op)) {
+    if (ZI->getSrcTy() == DestTy) {
+      // zext followed by trunc back to the original type preserves the value
+      // in the unsigned domain. It's safe to mark NUW.
+      if (!TI->hasNoUnsignedWrap()) {
+        TI->setHasNoUnsignedWrap(true);
+        ++NumNUW;
+        Changed = true;
+      }
+      // NSW is safe iff the original narrow value is proven to fit the signed
+      // range of DestTy. Use LVI to check the range of the zext source.
+      if (!TI->hasNoSignedWrap()) {
+        ConstantRange SrcRange =
+            LVI->getConstantRangeAtUse(ZI->getOperandUse(0), /*UndefAllowed=*/false);
+        APInt SignedMaxLimit = APInt::getSignedMaxValue(DestTy->getScalarSizeInBits());
+        // Require both non-negative and <= signed max of DestTy.
+        if (SrcRange.getSignedMin().isNonNegative() &&
+            SrcRange.getSignedMax().sle(SignedMaxLimit)) {
+          TI->setHasNoSignedWrap(true);
+          ++NumNSW;
+          Changed = true;
+        }
+      }
+      return Changed;
+    }
+  } else if (auto *SI = dyn_cast<SExtInst>(Op)) {
+    if (SI->getSrcTy() == DestTy) {
+      // sext followed by trunc back to the original type preserves the value
+      // in the signed domain. It's safe to mark NSW.
+      if (!TI->hasNoSignedWrap()) {
+        TI->setHasNoSignedWrap(true);
+        ++NumNSW;
+        Changed = true;
+      }
+      // We don't set NUW here; signed-preserving round-trip does not guarantee
+      // non-negative values.
+      return Changed;
+    }
+  }
+
+  // Do not add no-wrap flags if the trunc feeds into smin, as this may
+  // introduce poison-on-out-of-range miscompiles (see pr137582).
+  for (User *U : TI->users()) {
+    if (auto *CB = dyn_cast<CallBase>(U)) {
+      if (Function *F = CB->getCalledFunction()) {
+        if (F->getIntrinsicID() == Intrinsic::smin)
+          return Changed;
+      }
+    }
+  }
+
+  // Use LVI-based range checks to deduce NUW conservatively and NSW strictly.
   ConstantRange Range =
       LVI->getConstantRangeAtUse(TI->getOperandUse(0), /*UndefAllowed=*/false);
-  uint64_t DestWidth = TI->getDestTy()->getScalarSizeInBits();
-  bool Changed = false;

+  // NUW: Require full unsigned containment within destination unsigned range.
   if (!TI->hasNoUnsignedWrap()) {
-    if (Range.getActiveBits() <= DestWidth) {
+    unsigned SrcWidth = Op->getType()->getScalarSizeInBits();
+    APInt UnsignedMinLimit(SrcWidth, 0);
+    APInt UnsignedMaxLimit = APInt::getMaxValue(DestWidth).zext(SrcWidth);
+    if (Range.getUnsignedMin().uge(UnsignedMinLimit) &&
+        Range.getUnsignedMax().ule(UnsignedMaxLimit)) {
       TI->setHasNoUnsignedWrap(true);
       ++NumNUW;
       Changed = true;
     }
   }

+  // NSW: Require full signed containment within destination signed range.
   if (!TI->hasNoSignedWrap()) {
-    if (Range.getMinSignedBits() <= DestWidth) {
+    unsigned SrcWidth = Op->getType()->getScalarSizeInBits();
+    APInt SignedMinLimit = APInt::getSignedMinValue(DestWidth).sext(SrcWidth);
+    APInt SignedMaxLimit = APInt::getSignedMaxValue(DestWidth).sext(SrcWidth);
+    if (Range.getSignedMin().sge(SignedMinLimit) &&
+        Range.getSignedMax().sle(SignedMaxLimit)) {
       TI->setHasNoSignedWrap(true);
       ++NumNSW;
       Changed = true;

